insert into flashcard_decks (slug, topic_id, title, description, active) values
  ('as.hand-tools', 'as.hand-tools', 'Auto & Shop — Hand Tools', 'Identify the tool by what it''s used for. The ASVAB AS subtest leans on tool recognition.', true),
  ('ei.ohms-law-power', 'ei.ohms-law-power', 'Electronics — Ohm''s Law & Power', 'V = IR, P = IV, and the unit conversions you''ll see on the ASVAB EI subtest.', true),
