insert into flashcard_cards (deck_id, topic_id, difficulty, front, back, explanation, sort_order, active)
select
  d.id, c.topic_id, c.difficulty, c.front, c.back, c.explanation, c.sort_order, true
from (values
  ('as.hand-tools', 'as.hand-tools', 1, 'Used to drive nails into wood and pry them back out', 'Claw hammer', 'The curved claw on the back is for pulling nails; a framing hammer looks similar but has a straighter, longer claw for rough construction.', 1),
  ('as.hand-tools', 'as.hand-tools', 1, 'Used to drive screws with a single straight-slot head', 'Flathead (slotted) screwdriver', 'Also called a flat-blade or standard screwdriver; distinct from Phillips, Torx, or hex drivers because the tip is a flat blade.', 2),
  ('as.hand-tools', 'as.hand-tools', 1, 'Used to measure length by pulling out a flexible metal blade', 'Tape measure', 'The hooked end is intentionally loose so it reads accurately whether you push it against a surface or hook it over an edge.', 3),
  ('as.hand-tools', 'as.hand-tools', 2, 'Used to drive screws with a cross-shaped recess in the head', 'Phillips screwdriver', 'Designed to cam out under high torque to prevent overtightening; not interchangeable with Pozidriv or square-drive bits.', 4),
  ('as.hand-tools', 'as.hand-tools', 2, 'Used with interchangeable cylindrical heads to turn nuts and bolts quickly', 'Socket wrench (ratchet)', 'The ratcheting mechanism lets you turn a fastener without removing and repositioning the tool between strokes.', 5),
  ('as.hand-tools', 'as.hand-tools', 2, 'Used to grip and bend wire or reach into tight spaces with thin tapered jaws', 'Needle-nose pliers', 'Ideal for electrical work and small parts; differs from lineman''s pliers, which have flat gripping jaws and a side cutter.', 6),
  ('as.hand-tools', 'as.hand-tools', 2, 'Used to determine whether a surface is perfectly horizontal or vertical', 'Level (spirit level)', 'A bubble centered between the lines on the vial indicates true level or plumb depending on the vial''s orientation.', 7),
  ('as.hand-tools', 'as.hand-tools', 2, 'Used to cut metal pipe, rod, or bar stock with a thin replaceable blade in a frame', 'Hacksaw', 'The blade is tensioned in a C-shaped frame and is installed with the teeth pointing forward so it cuts on the push stroke.', 8),
  ('as.hand-tools', 'as.hand-tools', 2, 'Used to mark and check 90-degree corners when laying out wood', 'Combination square', 'The sliding head also checks 45-degree miters and includes a small bubble level and a scribe, unlike a fixed try square.', 9),
  ('as.hand-tools', 'as.hand-tools', 3, 'Used to drive recessed fasteners with a six-sided star-shaped tip', 'Hex (Allen) wrench / key', 'Often called an Allen wrench or hex key; the L-shape lets you switch between fast turning and high torque by flipping it.', 10),
  ('as.hand-tools', 'as.hand-tools', 3, 'Used to grip large nuts or pipes by sliding the lower jaw along an angled track', 'Channel-lock (water pump) pliers', 'The tongue-and-groove channels let you set a wide jaw opening that won''t slip closed under load, unlike basic slip-joint pliers.', 11),
  ('as.hand-tools', 'as.hand-tools', 3, 'Used to shape metal by striking with a rounded face on one end and a hemispherical face on the other', 'Ball-peen hammer', 'The rounded peen is used for peening rivets and shaping metal; a claw hammer''s softer steel would deform if struck on metal stock.', 12),
  ('as.hand-tools', 'as.hand-tools', 3, 'Used to measure inside, outside, and depth dimensions to about a thousandth of an inch', 'Calipers (vernier or digital)', 'More versatile than a micrometer because of the four measuring surfaces, but typically less precise than a micrometer at the same range.', 13),
  ('as.hand-tools', 'as.hand-tools', 3, 'Used to tighten a fastener to a precise, specified amount of rotational force', 'Torque wrench', 'A click-type wrench releases or signals when the set torque is reached; critical for lug nuts, head bolts, and other engineered joints.', 14),
  ('as.hand-tools', 'as.hand-tools', 3, 'Used to grip irregular objects by clamping with adjustable, locking jaws', 'Locking pliers (Vise-Grip)', 'An over-center toggle holds the jaws shut hands-free, unlike standard pliers that rely on continuous hand pressure.', 15),
  ('as.hand-tools', 'as.hand-tools', 4, 'Used to grip and turn round pipe by digging serrated jaws into the pipe wall', 'Pipe wrench (Stillson wrench)', 'The angled, toothed jaws bite harder as you pull, leaving marks; a smooth-jawed adjustable wrench would slip on round pipe.', 16),
  ('as.hand-tools', 'as.hand-tools', 4, 'Used to deliver heavy blows without bouncing back or marring the workpiece', 'Dead-blow hammer', 'The hollow head is filled with shot or sand that absorbs the rebound; a rubber mallet is similar but lighter and bouncier.', 17),
  ('as.hand-tools', 'as.hand-tools', 4, 'Used to measure outside dimensions to a thousandth of an inch using a calibrated thimble and spindle', 'Micrometer', 'Reads to 0.001" on a standard mechanical micrometer (vernier scale extends to 0.0001"); limited to about a one-inch range per tool, so machinists own a set.', 18),
  ('as.hand-tools', 'as.hand-tools', 4, 'Used to drive a stuck pin out of a hole after a starter punch has loosened it', 'Drift punch (pin punch)', 'Has a long straight shank of constant diameter so it can pass deep into the hole; a center punch has a tapered tip for marking, not driving.', 19),
  ('as.hand-tools', 'as.hand-tools', 5, 'Used to cut wood along the grain with chisel-like teeth that act like tiny gouges', 'Rip saw', 'Rip-saw teeth are filed straight across to chisel out fibers along the grain; a crosscut saw has knife-like beveled teeth that sever fibers across the grain.', 20),
  ('ei.ohms-law-power', 'ei.ohms-law-power', 1, 'Identify the unit: what does a volt (V) measure?', 'Voltage — electrical potential difference (V)', 'The volt is the SI unit of electric potential and electromotive force; symbol V.', 1),
  ('ei.ohms-law-power', 'ei.ohms-law-power', 1, 'What does the symbol Ω represent?', 'The ohm — the unit of electrical resistance', 'Ω (capital Greek omega) is the SI symbol for ohms; 1 Ω = 1 V/A.', 2),
  ('ei.ohms-law-power', 'ei.ohms-law-power', 2, 'Ohm''s law: voltage equals what?', 'V = I × R (current times resistance)', 'V in volts, I in amps, R in ohms. Rearranged: I = V/R and R = V/I.', 3),
  ('ei.ohms-law-power', 'ei.ohms-law-power', 2, 'Write the formula for electrical power in terms of current and voltage.', 'P = I × V (watts = amps × volts)', 'Power equals current multiplied by voltage; the unit is the watt (W).', 4),
  ('ei.ohms-law-power', 'ei.ohms-law-power', 2, 'What does an ammeter measure, and in what unit?', 'Current, measured in amperes (amps, A)', 'Current is the rate of charge flow; 1 amp = 1 coulomb per second.', 5),
  ('ei.ohms-law-power', 'ei.ohms-law-power', 2, 'Convert: 250 mA equals how many amps?', '0.25 A', 'Milli- means one-thousandth, so 1 mA = 0.001 A; 250 × 0.001 = 0.25 A.', 6),
  ('ei.ohms-law-power', 'ei.ohms-law-power', 3, 'Calculate: 12 V is applied across a 4 Ω resistor. What is the current?', '3 A', 'I = V/R = 12 / 4 = 3 A.', 7),
  ('ei.ohms-law-power', 'ei.ohms-law-power', 3, 'A 60 W bulb runs on 120 V. How much current does it draw?', '0.5 A', 'I = P/V = 60 / 120 = 0.5 A.', 8),
  ('ei.ohms-law-power', 'ei.ohms-law-power', 3, 'Convert: 2.2 kΩ equals how many ohms?', '2,200 Ω', 'Kilo- means one thousand, so 1 kΩ = 1,000 Ω; 2.2 × 1,000 = 2,200 Ω.', 9),
  ('ei.ohms-law-power', 'ei.ohms-law-power', 3, 'Write the power formula that uses current and resistance only.', 'P = I² × R', 'Substitute V = IR into P = IV to get P = I²R; useful when V is unknown.', 10),
  ('ei.ohms-law-power', 'ei.ohms-law-power', 3, 'Two 10 Ω resistors are wired in series. What is the total resistance?', '20 Ω', 'In series, resistances add: R_total = R1 + R2 = 10 + 10 = 20 Ω.', 11),
  ('ei.ohms-law-power', 'ei.ohms-law-power', 4, 'Calculate the power dissipated by a 5 Ω resistor carrying 2 A.', '20 W', 'P = I²R = (2)² × 5 = 4 × 5 = 20 W.', 12),
  ('ei.ohms-law-power', 'ei.ohms-law-power', 4, 'A 240 V source connects to a 60 Ω heater. How many watts does it dissipate?', '960 W', 'P = V²/R = (240)² / 60 = 57,600 / 60 = 960 W.', 13),
  ('ei.ohms-law-power', 'ei.ohms-law-power', 4, 'A 9 V battery pushes 30 mA through a resistor. What is the resistor''s value?', '300 Ω', 'Convert 30 mA = 0.03 A, then R = V/I = 9 / 0.03 = 300 Ω.', 14),
  ('ei.ohms-law-power', 'ei.ohms-law-power', 5, 'Two 10 Ω resistors are wired in parallel across 20 V. What is the total current from the source?', '4 A', 'Parallel: 1/R_t = 1/10 + 1/10 = 2/10, so R_t = 5 Ω; I = V/R = 20/5 = 4 A.', 15),
  ('mk.geometry', 'mk.geometry', 1, 'Area of a rectangle?', 'A = length × width', 'A square is the special case where length = width, so A = s².', 1),
  ('mk.geometry', 'mk.geometry', 1, 'Sum of interior angles in any triangle?', '180°', 'True for every triangle — if you know two angles, subtract their sum from 180° to find the third.', 2),
  ('mk.geometry', 'mk.geometry', 1, 'What does π (pi) approximately equal?', 'π ≈ 3.14', 'π is the ratio of a circle''s circumference to its diameter — same for every circle.', 3),
  ('mk.geometry', 'mk.geometry', 1, 'Perimeter of a square with side s?', 'P = 4s', 'All four sides are equal, so add s four times — distinct from area (s²) and from the rectangle perimeter formula.', 4),
  ('mk.geometry', 'mk.geometry', 2, 'Area of a square with side s?', 'A = s²', 'Just length × width where both sides equal s — don''t confuse with perimeter (4s).', 5),
  ('mk.geometry', 'mk.geometry', 2, 'Perimeter of a rectangle?', 'P = 2 × (length + width)', 'Equivalent to 2L + 2W — add all four sides; opposite sides are equal.', 6),
  ('mk.geometry', 'mk.geometry', 2, 'Area of a circle with radius r?', 'A = πr²', 'Square the radius first, then multiply by π — common mistake is to use diameter instead of radius.', 7),
  ('mk.geometry', 'mk.geometry', 2, 'Two angles are complementary if their sum is...?', '90°', 'Complementary = Corner (90°); the alphabetical pairing with supplementary helps you remember the order.', 8),
  ('mk.geometry', 'mk.geometry', 2, 'Two angles are supplementary if their sum is...?', '180°', 'Supplementary = Straight line (180°) — two angles on a straight line are always supplementary.', 9),
  ('mk.geometry', 'mk.geometry', 2, 'Diameter of a circle in terms of radius?', 'd = 2r', 'The diameter passes through the center and equals twice the radius.', 10),
  ('mk.geometry', 'mk.geometry', 2, 'Volume of a cube with side s?', 'V = s³', 'Length × width × height where all three are s — units are cubic (e.g., cm³).', 11),
  ('mk.geometry', 'mk.geometry', 2, 'Volume of a rectangular prism (box)?', 'V = length × width × height', 'Generalizes the cube formula — when l = w = h = s, this collapses to V = s³.', 12),
  ('mk.geometry', 'mk.geometry', 3, 'Area of a triangle?', 'A = ½ × b × h', 'The ½ comes from the fact that a triangle is half a parallelogram with the same base and height.', 13),
  ('mk.geometry', 'mk.geometry', 3, 'Pythagorean theorem?', 'a² + b² = c²', 'Only works for right triangles; c is always the hypotenuse (longest side, opposite the right angle).', 14),
  ('mk.geometry', 'mk.geometry', 3, 'Circumference of a circle?', 'C = 2πr or πd', 'Both forms are equal because diameter = 2r — pick whichever matches the given measurement.', 15),
  ('mk.geometry', 'mk.geometry', 3, 'Area of a parallelogram?', 'A = b × h', 'Use the perpendicular height, NOT the slanted side — same formula as a rectangle since you can rearrange it into one.', 16),
  ('mk.geometry', 'mk.geometry', 3, 'Area of a trapezoid?', 'A = ½ × (b₁ + b₂) × h', 'Average the two parallel bases, then multiply by the perpendicular height between them.', 17),
  ('mk.geometry', 'mk.geometry', 3, 'Volume of a cylinder?', 'V = πr²h', 'It''s the area of the circular base (πr²) times the height — same pattern as any prism: base area × height.', 18),
  ('mk.geometry', 'mk.geometry', 4, 'Common Pythagorean triples to memorize?', '3-4-5 and 5-12-13 (and their multiples like 6-8-10)', 'Spotting these saves time — if two sides match a known triple, the third is automatic, no calculation needed.', 19),
  ('mk.geometry', 'mk.geometry', 4, 'What''s true about vertical angles (formed by two intersecting lines)?', 'Vertical angles are equal', 'The two pairs of opposite (across-the-X) angles formed by intersecting lines always have equal measures.', 20),
  ('mk.geometry', 'mk.geometry', 4, 'Side ratio of a 30-60-90 triangle (opposite 30°, 60°, 90°)?', '1 : √3 : 2', 'Shortest side is opposite 30°; hypotenuse (opposite 90°) is twice the shortest — middle side equals shortest × √3.', 21),
  ('mk.geometry', 'mk.geometry', 4, 'Volume of a sphere with radius r?', 'V = (4/3)πr³', 'Cube the radius, then multiply by 4π/3 — don''t confuse with surface area (4πr²).', 22),
  ('mk.geometry', 'mk.geometry', 5, 'Side ratio of a 45-45-90 (isosceles right) triangle?', '1 : 1 : √2', 'Both legs are equal; the hypotenuse is a leg times √2 — comes straight from a² + a² = c², so c = a√2.', 23),
  ('wk.prefixes-suffixes', 'wk.prefixes-suffixes', 1, 'UN-', 'not, opposite of (prefix)', 'Examples: unhappy (not happy), undo (reverse an action), unable (not able).', 1),
  ('wk.prefixes-suffixes', 'wk.prefixes-suffixes', 1, 'RE-', 'again, back (prefix)', 'Examples: redo (do again), return (go back), rebuild (build again).', 2),
  ('wk.prefixes-suffixes', 'wk.prefixes-suffixes', 1, '-LESS', 'without (suffix)', 'Examples: hopeless (without hope), fearless (without fear), endless (without end).', 3),
  ('wk.prefixes-suffixes', 'wk.prefixes-suffixes', 2, 'PRE-', 'before (prefix)', 'Examples: preview (view before), prepare (ready before), predict (say before).', 4),
  ('wk.prefixes-suffixes', 'wk.prefixes-suffixes', 2, 'POST-', 'after (prefix)', 'Examples: postwar (after war), postpone (put after), postscript (added after writing).', 5),
  ('wk.prefixes-suffixes', 'wk.prefixes-suffixes', 2, 'MIS-', 'wrongly, badly (prefix)', 'Examples: misspell (spell wrongly), misjudge (judge wrongly), misplace (put in wrong place).', 6),
  ('wk.prefixes-suffixes', 'wk.prefixes-suffixes', 2, '-ABLE/-IBLE', 'capable of, able to be (suffix)', 'Examples: readable (able to be read), edible (able to be eaten), flexible (able to bend).', 7),
  ('wk.prefixes-suffixes', 'wk.prefixes-suffixes', 2, '-NESS', 'state or quality of (suffix)', 'Examples: kindness (state of being kind), darkness (state of being dark), happiness (state of being happy).', 8),
  ('wk.prefixes-suffixes', 'wk.prefixes-suffixes', 2, '-MENT', 'act, process, or result of (suffix)', 'Examples: agreement (act of agreeing), movement (act of moving), achievement (result of achieving).', 9),
  ('wk.prefixes-suffixes', 'wk.prefixes-suffixes', 3, 'ANTE-', 'before (prefix)', 'Examples: antebellum (before war), antecedent (something that comes before), anterior (front-positioned).', 10),
  ('wk.prefixes-suffixes', 'wk.prefixes-suffixes', 3, 'ANTI-', 'against, opposed to (prefix)', 'Examples: antiwar (against war), antibiotic (against bacteria), antifreeze (prevents freezing).', 11),
  ('wk.prefixes-suffixes', 'wk.prefixes-suffixes', 3, 'CIRCUM-', 'around (prefix)', 'Examples: circumnavigate (sail around), circumference (distance around a circle), circumvent (go around).', 12),
  ('wk.prefixes-suffixes', 'wk.prefixes-suffixes', 3, 'INTER-', 'between, among (prefix)', 'Examples: international (between nations), intervene (come between), intersect (cross between).', 13),
  ('wk.prefixes-suffixes', 'wk.prefixes-suffixes', 3, '-ITY', 'state, quality, or condition of (suffix)', 'Examples: clarity (quality of being clear), purity (state of being pure), activity (state of being active).', 14),
  ('wk.prefixes-suffixes', 'wk.prefixes-suffixes', 3, '-OUS', 'full of, having the quality of (suffix)', 'Examples: dangerous (full of danger), joyous (full of joy), nervous (full of nerves).', 15),
  ('wk.prefixes-suffixes', 'wk.prefixes-suffixes', 4, 'CONTRA-', 'against, opposite (prefix)', 'Examples: contradict (speak against), contraband (goods against the law), contrary (opposite in nature).', 16),
  ('wk.prefixes-suffixes', 'wk.prefixes-suffixes', 4, 'INTRA-', 'within, inside (prefix)', 'Examples: intramural (within walls/within a school), intravenous (within a vein), intrastate (within a state).', 17),
  ('wk.prefixes-suffixes', 'wk.prefixes-suffixes', 4, 'OMNI-', 'all, every (prefix)', 'Examples: omnipotent (all-powerful), omnivore (eats all kinds of food), omnipresent (present everywhere).', 18),
  ('wk.prefixes-suffixes', 'wk.prefixes-suffixes', 4, '-TUDE', 'state or quality of (suffix)', 'Examples: solitude (state of being alone), gratitude (quality of being thankful), magnitude (quality of greatness).', 19),
  ('wk.prefixes-suffixes', 'wk.prefixes-suffixes', 5, '-WISE', 'in the manner or direction of (suffix)', 'Examples: clockwise (in the direction of a clock), lengthwise (in the direction of length), otherwise (in another manner).', 20),
  ('wk.root-words', 'wk.root-words', 1, 'BIO', 'life', 'Examples: biology (study of life), biography (written account of a life), antibiotic (against living microbes).', 1),
  ('wk.root-words', 'wk.root-words', 1, 'GEO', 'earth or land', 'Examples: geology (study of the earth), geography (description of the earth), geothermal (heat from the earth).', 2),
  ('wk.root-words', 'wk.root-words', 1, 'PHON', 'sound', 'Examples: telephone (distant sound), symphony (sounds together), cacophony (harsh sound).', 3),
  ('wk.root-words', 'wk.root-words', 2, 'BENE', 'good or well', 'Examples: benevolent (well-wishing), beneficial (producing good), benefactor (one who does good).', 4),
  ('wk.root-words', 'wk.root-words', 2, 'MAL', 'bad or evil', 'Examples: malevolent (wishing harm), malign (to speak evil of), malady (a bad condition or illness).', 5),
  ('wk.root-words', 'wk.root-words', 2, 'AUD', 'to hear', 'Examples: audible (able to be heard), auditorium (place for hearing), audition (a hearing or trial).', 6),
  ('wk.root-words', 'wk.root-words', 2, 'DICT', 'to say or speak', 'Examples: dictate (to speak orders), verdict (a spoken truth), edict (an official statement).', 7),
  ('wk.root-words', 'wk.root-words', 2, 'PORT', 'to carry', 'Examples: portable (able to be carried), transport (carry across), deport (to carry away or expel).', 8),
  ('wk.root-words', 'wk.root-words', 2, 'SPECT', 'to look or see', 'Examples: inspect (look into), spectator (one who watches), circumspect (looking around, cautious).', 9),
  ('wk.root-words', 'wk.root-words', 3, 'VID/VIS', 'to see', 'Examples: visible (able to be seen), evident (clearly seen), envision (to see in the mind).', 10),
  ('wk.root-words', 'wk.root-words', 3, 'SCRIB/SCRIPT', 'to write', 'Examples: inscribe (to write into), manuscript (handwritten document), prescribe (to write an order for).', 11),
  ('wk.root-words', 'wk.root-words', 3, 'CRED', 'to believe or trust', 'Examples: credible (believable), incredulous (unbelieving), credentials (proof that earns trust).', 12),
  ('wk.root-words', 'wk.root-words', 3, 'JECT', 'to throw', 'Examples: eject (throw out), interject (throw between), trajectory (path of something thrown).', 13),
  ('wk.root-words', 'wk.root-words', 3, 'MIT/MISS', 'to send', 'Examples: transmit (send across), emissary (one sent on a mission), remit (to send back).', 14),
  ('wk.root-words', 'wk.root-words', 3, 'CHRON', 'time', 'Examples: chronological (arranged by time), anachronism (out of its time), synchronize (occur at the same time).', 15),
  ('wk.root-words', 'wk.root-words', 4, 'FRACT/FRAG', 'to break', 'Examples: fracture (a break), refract (to break light''s path), infraction (a breaking of rules).', 16),
  ('wk.root-words', 'wk.root-words', 4, 'MORPH', 'shape or form', 'Examples: metamorphosis (change of form), amorphous (without shape), anthropomorphic (having human form).', 17),
  ('wk.root-words', 'wk.root-words', 4, 'ANTHRO', 'human or mankind', 'Examples: anthropology (study of humans), misanthrope (one who hates people), philanthropy (love of mankind).', 18),
  ('wk.root-words', 'wk.root-words', 4, 'FID', 'faith or trust', 'Examples: fidelity (faithfulness), confidant (trusted friend), perfidy (breaking of faith, treachery).', 19),
  ('wk.root-words', 'wk.root-words', 5, 'GNOS', 'to know', 'Examples: prognosis (foreknowledge of an outcome), agnostic (one without knowledge of the divine), diagnostic (distinguishing through knowledge).', 20),
  ('wk.synonyms', 'wk.synonyms', 1, 'HOSTILE', 'unfriendly or aggressive', 'Common ASVAB synonym pairing: hostile ≈ antagonistic, belligerent, adversarial.', 1),
  ('wk.synonyms', 'wk.synonyms', 1, 'EAGER', 'enthusiastic or keen', 'Common ASVAB synonym pairing: eager ≈ enthusiastic, zealous, avid.', 2),
  ('wk.synonyms', 'wk.synonyms', 1, 'BRIEF', 'short or concise', 'Common ASVAB synonym pairing: brief ≈ concise, short, succinct.', 3),
  ('wk.synonyms', 'wk.synonyms', 1, 'WEARY', 'tired or exhausted', 'Common ASVAB synonym pairing: weary ≈ fatigued, exhausted, drained.', 4),
  ('wk.synonyms', 'wk.synonyms', 2, 'ABATE', 'to lessen or reduce', 'Common ASVAB synonym pairing: abate ≈ diminish, decrease, subside.', 5),
  ('wk.synonyms', 'wk.synonyms', 2, 'BENIGN', 'kind or harmless', 'Common ASVAB synonym pairing: benign ≈ harmless, mild, gentle.', 6),
  ('wk.synonyms', 'wk.synonyms', 2, 'CANDID', 'honest or frank', 'Common ASVAB synonym pairing: candid ≈ frank, straightforward, blunt.', 7),
  ('wk.synonyms', 'wk.synonyms', 2, 'DEFER', 'to postpone or delay', 'Common ASVAB synonym pairing: defer ≈ postpone, delay, suspend.', 8),
  ('wk.synonyms', 'wk.synonyms', 2, 'EMINENT', 'famous or distinguished', 'Common ASVAB synonym pairing: eminent ≈ distinguished, prominent, renowned.', 9),
  ('wk.synonyms', 'wk.synonyms', 2, 'DETER', 'to discourage or prevent', 'Common ASVAB synonym pairing: deter ≈ discourage, dissuade, hinder.', 10),
  ('wk.synonyms', 'wk.synonyms', 2, 'VIVID', 'bright or striking', 'Common ASVAB synonym pairing: vivid ≈ bright, intense, vibrant.', 11),
  ('wk.synonyms', 'wk.synonyms', 2, 'RESOLVE', 'to settle or decide firmly', 'Common ASVAB synonym pairing: resolve ≈ determine, settle, conclude.', 12),
  ('wk.synonyms', 'wk.synonyms', 3, 'FRUGAL', 'thrifty or economical', 'Common ASVAB synonym pairing: frugal ≈ thrifty, economical, sparing.', 13),
  ('wk.synonyms', 'wk.synonyms', 3, 'DISCERN', 'to perceive or distinguish', 'Common ASVAB synonym pairing: discern ≈ perceive, detect, distinguish.', 14),
  ('wk.synonyms', 'wk.synonyms', 3, 'INNATE', 'inborn or natural', 'Common ASVAB synonym pairing: innate ≈ inborn, inherent, intrinsic.', 15),
  ('wk.synonyms', 'wk.synonyms', 3, 'LUCID', 'clear or easily understood', 'Common ASVAB synonym pairing: lucid ≈ clear, coherent, intelligible.', 16),
  ('wk.synonyms', 'wk.synonyms', 3, 'PRUDENT', 'cautious and wise', 'Common ASVAB synonym pairing: prudent ≈ cautious, sensible, judicious.', 17),
  ('wk.synonyms', 'wk.synonyms', 3, 'TACITURN', 'quiet or reserved in speech', 'Common ASVAB synonym pairing: taciturn ≈ reserved, reticent, uncommunicative.', 18),
  ('wk.synonyms', 'wk.synonyms', 3, 'MITIGATE', 'to make less severe', 'Common ASVAB synonym pairing: mitigate ≈ alleviate, ease, lessen.', 19),
  ('wk.synonyms', 'wk.synonyms', 3, 'AMBIGUOUS', 'unclear or open to interpretation', 'Common ASVAB synonym pairing: ambiguous ≈ vague, unclear, equivocal.', 20),
  ('wk.synonyms', 'wk.synonyms', 4, 'OBSTINATE', 'stubborn and unyielding', 'Common ASVAB synonym pairing: obstinate ≈ stubborn, headstrong, intractable.', 21),
  ('wk.synonyms', 'wk.synonyms', 4, 'NEFARIOUS', 'wicked or evil', 'Common ASVAB synonym pairing: nefarious ≈ wicked, villainous, iniquitous.', 22),
  ('wk.synonyms', 'wk.synonyms', 4, 'SAGACIOUS', 'wise and shrewd', 'Common ASVAB synonym pairing: sagacious ≈ wise, shrewd, astute.', 23),
  ('wk.synonyms', 'wk.synonyms', 4, 'RECONDITE', 'obscure or hard to understand', 'Common ASVAB synonym pairing: recondite ≈ obscure, abstruse, esoteric.', 24),
